problems.solution:
function calculateOxygen(astronauts, days) {
  return astronauts * 550 * days;
}

function willFlowersFit(flowerCount, gardenLengthCm) {
  return flowerCount * 45 <= gardenLengthCm;
}

function isPasswordValid(password) {
  return password.length >= 8;
}

function countTreasure(gold, silver, copper) {
  return gold * 10000 + silver * 100 + copper;
}

function calculateScore(fieldGoals, threePointers, freeThrows) {
  return fieldGoals * 2 + threePointers * 3 + freeThrows;
}

function calculateFrequency(octaveOffset) {
  return 440 * Math.pow(2, octaveOffset);
}

function calculateSpacing(paintingCount) {
  return 12 / paintingCount;
}

function romanToNumber(roman) {
  const values = {I: 1, V: 5, X: 10, L: 50, C: 100, D: 500, M: 1000};
  let total = 0;
  for (let char of roman) {
    total += values[char];
  }
  return total;
}

function getBatteryPercentage(currentCharge) {
  return Math.floor((currentCharge / 5000) * 100);
}

function calculateLateFee(daysLate) {
  return daysLate * 0.25;
}

function calculateMigrationDistance(trips) {
  return trips * 71000;
}

function calculateLoadTime(images, scripts, cssFiles) {
  return images * 0.15 + scripts * 0.08 + cssFiles * 0.05;
}

function calculateSpellPower(intelligence, staffBonus) {
  return intelligence * 3 + staffBonus;
}

function calculatePace(targetMinutes) {
  return Math.round((targetMinutes / 42.195) * 100) / 100;
}

function getStringFrequency(stringName) {
  const frequencies = {E2: 82.41, A2: 110, D3: 146.83, G3: 196, B3: 246.94, E4: 329.63};
  return frequencies[stringName] || 0;
}

function calculatePaintCost(redLiters, blueLiters, yellowLiters) {
  return redLiters * 12 + blueLiters * 15 + yellowLiters * 10;
}

function calculateBlocks(levels) {
  let total = 0;
  for (let i = 1; i <= levels; i++) {
    total += i * i;
  }
  return total;
}

function calculateFuel(distanceKm) {
  return (distanceKm / 1000) * 8.5;
}

function calculateCookieCost(cookieCount) {
  const freeCookies = Math.floor(cookieCount / 4);
  const paidCookies = cookieCount - freeCookies;
  return paidCookies * 2;
}

function estimateTreeAge(diameterCm) {
  return Math.floor(diameterCm / 2.5);
}

function is4KScreen(width, height) {
  return width >= 3840 && height >= 2160;
}

function calculateTournamentScore(joustsWon, archeryHits, meleeWins) {
  return joustsWon * 10 + archeryHits * 5 + meleeWins * 15;
}

function calculateSwimDistance(laps) {
  return laps * 100;
}

function findKeyPosition(keyNumber) {
  if (keyNumber < 40) return 'left';
  if (keyNumber > 40) return 'right';
  return 'middle';
}

function calculateMaterialCost(bronzeKg, marbleKg, woodKg) {
  return bronzeKg * 45 + marbleKg * 30 + woodKg * 8;
}

function calculateFoodSupplies(colonists) {
  return colonists * 2.5 * 270;
}

function calculateTaxiFare(kilometers) {
  return 3.50 + kilometers * 2.00;
}

function calculateHoneyProduction(beehives) {
  return beehives * 25;
}

function convertSignalStrength(dbm) {
  return Math.max(0, Math.min(100, Math.round((dbm + 90) / 60 * 100)));
}

function calculateArcheryScore(bullseyes, innerRing, outerRing) {
  return bullseyes * 10 + innerRing * 8 + outerRing * 5;
}

function isSetComplete(player1Games, player2Games) {
  if (player1Games >= 6 && player1Games - player2Games >= 2) return true;
  if (player2Games >= 6 && player2Games - player1Games >= 2) return true;
  return false;
}

function getDrumForBeat(beatNumber) {
  if (beatNumber === 1 || beatNumber === 3) return 'kick';
  if (beatNumber === 2 || beatNumber === 4) return 'snare';
  return 'rest';
}

function calculatePrimaryTiles(width, height) {
  let count = 0;
  for (let row = 0; row < height; row++) {
    for (let col = 0; col < width; col++) {
      if ((row + col) % 2 === 0) {
        count++;
      }
    }
  }
  return count;
}

function maxReviewPairs(juniors, seniors, maxDiff) {
  juniors.sort((a, b) => a - b);
  seniors.sort((a, b) => a - b);

  let i = 0, j = 0, pairs = 0;

  while (i < juniors.length && j < seniors.length) {
    if (Math.abs(juniors[i] - seniors[j]) <= maxDiff) {
      pairs++;
      i++;
      j++;
    } else if (juniors[i] < seniors[j]) {
      i++;
    } else {
      j++;
    }
  }

  return pairs;
}

function canHarmonizeIngredients(ingredients, pairs) {
  const counts = {};

  for (const ing of ingredients) {
    counts[ing] = (counts[ing] || 0) + 1;
  }

  for (const elem of Object.keys(counts)) {
    const complement = pairs[elem];
    if (!complement) return false;
    if (counts[elem] !== (counts[complement] || 0)) return false;
  }

  return true;
}

function countAnomalousWindows(packets, windowSize, threshold) {
  if (packets.length < windowSize) return 0;

  let count = 0;
  let windowSum = 0;

  for (let i = 0; i < windowSize; i++) {
    windowSum += packets[i];
  }

  if (windowSum / windowSize > threshold) count++;

  for (let i = windowSize; i < packets.length; i++) {
    windowSum = windowSum - packets[i - windowSize] + packets[i];
    if (windowSum / windowSize > threshold) count++;
  }

  return count;
}

function countStableWeatherPeriods(temps, threshold, minDays) {
  let count = 0;
  const n = temps.length;

  for (let i = 0; i < n; i++) {
    let min = temps[i], max = temps[i];
    for (let j = i; j < n; j++) {
      min = Math.min(min, temps[j]);
      max = Math.max(max, temps[j]);
      if (max - min < threshold && j - i + 1 >= minDays) {
        count++;
      }
    }
  }

  return count;
}

function countGrowthWindows(sales, minDays) {
  let count = 0;
  let start = 0;

  for (let i = 1; i <= sales.length; i++) {
    if (i === sales.length || sales[i] < sales[i - 1]) {
      const windowLen = i - start;
      if (windowLen >= minDays) {
        count += (windowLen - minDays + 1) * (windowLen - minDays + 2) / 2;
      }
      start = i;
    }
  }

  return count;
}

function detectManaSurges(manaLevels, threshold, minDuration) {
  let surges = 0;
  let currentStreak = 0;

  for (const level of manaLevels) {
    if (level > threshold) {
      currentStreak++;
    } else {
      if (currentStreak >= minDuration) {
        surges++;
      }
      currentStreak = 0;
    }
  }

  if (currentStreak >= minDuration) {
    surges++;
  }

  return surges;
}

function minFuelCost(distances, prices, capacity, target) {
  const n = distances.length;
  const dp = new Array(n).fill(Infinity);
  dp[0] = 0;

  for (let i = 1; i < n; i++) {
    const dist = distances[i] - distances[i - 1];
    if (dist > capacity) {
      return -1;
    }
    dp[i] = dp[i - 1] + dist * prices[i - 1];
  }

  if (target > distances[n - 1]) {
    const distToTarget = target - distances[n - 1];
    if (distToTarget > capacity) {
      return -1;
    }
    return dp[n - 1] + distToTarget * prices[n - 1];
  }

  return dp[n - 1];
}

function maxOnTimeTasks(tasks) {
  tasks.sort((a, b) => a.deadline - b.deadline);
  const n = tasks.length;
  const dp = new Array(n + 1).fill(0);

  for (let i = 1; i <= n; i++) {
    for (let j = i; j >= 1; j--) {
      if (dp[j - 1] + tasks[i - 1].duration <= tasks[i - 1].deadline) {
        dp[j] = Math.max(dp[j], dp[j - 1] + tasks[i - 1].duration);
      }
    }
  }

  for (let i = n; i >= 0; i--) {
    if (dp[i] > 0 || i === 0) return i;
  }
  return 0;
}

function maxHoneyCollection(honeycomb) {
  if (honeycomb.length === 0) return 0;

  const dp = honeycomb[honeycomb.length - 1].slice();

  for (let row = honeycomb.length - 2; row >= 0; row--) {
    for (let col = 0; col < honeycomb[row].length; col++) {
      dp[col] = honeycomb[row][col] + Math.max(dp[col], dp[col + 1]);
    }
  }

  return dp[0];
}

function maxPortfolioReturn(budget, investments) {
  const dp = new Array(budget + 1).fill(0);

  for (const inv of investments) {
    for (let b = budget; b >= inv.cost; b--) {
      dp[b] = Math.max(dp[b], dp[b - inv.cost] + inv.return);
    }
  }

  return dp[budget];
}

function maxTreasureGold(dungeon, startHealth) {
  const rows = dungeon.length;
  const cols = dungeon[0].length;

  const dp = Array.from({length: rows}, () => new Array(cols).fill(-Infinity));

  if (startHealth + dungeon[0][0] > 0) {
    dp[0][0] = Math.max(0, dungeon[0][0]);
  }

  for (let i = 0; i < rows; i++) {
    for (let j = 0; j < cols; j++) {
      if (dp[i][j] === -Infinity) continue;

      if (j + 1 < cols && startHealth + dp[i][j] + dungeon[i][j + 1] > 0) {
        dp[i][j + 1] = Math.max(dp[i][j + 1], dp[i][j] + Math.max(0, dungeon[i][j + 1]));
      }
      if (i + 1 < rows && startHealth + dp[i][j] + dungeon[i + 1][j] > 0) {
        dp[i + 1][j] = Math.max(dp[i + 1][j], dp[i][j] + Math.max(0, dungeon[i + 1][j]));
      }
    }
  }

  return dp[rows - 1][cols - 1] === -Infinity ? 0 : dp[rows - 1][cols - 1];
}

function minClimbingEnergy(holds, maxReach) {
  const n = holds.length;
  const dp = new Array(n).fill(Infinity);
  dp[0] = 0;

  for (let i = 1; i < n; i++) {
    for (let j = 0; j < i; j++) {
      if (holds[i].height - holds[j].height <= maxReach) {
        dp[i] = Math.min(dp[i], dp[j] + holds[i].energy);
      }
    }
  }

  return dp[n - 1] === Infinity ? -1 : dp[n - 1];
}

function minChordTransitionCost(chords, transitionCost) {
  if (chords.length === 0) return 0;

  let totalCost = chords[0].cost;

  for (let i = 1; i < chords.length; i++) {
    totalCost += chords[i].cost;
    const transition = chords[i - 1].name + "-" + chords[i].name;
    totalCost += transitionCost[transition] || 0;
  }

  return totalCost;
}

function simplifyRoverPath(commands) {
  const stack = [];
  const cancel = { 'F': 'B', 'B': 'F', 'L': 'R', 'R': 'L' };

  for (const cmd of commands) {
    if (stack.length > 0 && stack[stack.length - 1] === cancel[cmd]) {
      stack.pop();
    } else {
      stack.push(cmd);
    }
  }

  return stack.join('');
}

function calculateSpecificityWinner(selectors) {
  let maxScore = -1;
  let winner = '';

  for (const selector of selectors) {
    let ids = 0, classes = 0, elements = 0;
    const tokens = selector.split(/\s+/);

    for (const token of tokens) {
      if (token.startsWith('#')) {
        ids++;
      } else if (token.startsWith('.')) {
        classes++;
      } else {
        elements++;
      }

      for (const char of token) {
        if (char === '#') ids++;
        else if (char === '.') classes++;
      }
    }

    const score = ids * 100 + classes * 10 + elements;
    if (score > maxScore) {
      maxScore = score;
      winner = selector;
    }
  }

  return winner;
}

function validateTunnelStructure(blueprint) {
  const stack = [];
  const pairs = { '(': ')', '[': ']', '{': '}' };

  for (const char of blueprint) {
    if (pairs[char]) {
      stack.push(char);
    } else if (Object.values(pairs).includes(char)) {
      if (stack.length === 0 || pairs[stack.pop()] !== char) {
        return false;
      }
    }
  }

  return stack.length === 0;
}

function unlockAncientDoor(sequence, pattern) {
  // Door opens if sequence forms a palindrome containing the pattern
  const isPalindrome = sequence === sequence.split('').reverse().join('');
  if (!isPalindrome) return false;
  return sequence.includes(pattern);
}

function validateGymnasticsRoutine(routine) {
  const stack = [];
  let i = 0;

  while (i < routine.length) {
    if (routine[i] === '<') {
      const closeIdx = routine.indexOf('>', i);
      if (closeIdx === -1) return false;

      const tag = routine.substring(i + 1, closeIdx);

      if (tag.startsWith('/')) {
        const tagName = tag.substring(1);
        if (stack.length === 0 || stack.pop() !== tagName) {
          return false;
        }
      } else if (!tag.endsWith('/')) {
        stack.push(tag);
      }

      i = closeIdx + 1;
    } else {
      i++;
    }
  }

  return stack.length === 0;
}

function detectTimelineParadoxes(events) {
  const graph = {};
  const visited = new Set();
  const recStack = new Set();

  for (const e of events) {
    if (!graph[e.id]) graph[e.id] = [];
    for (const before of e.before) {
      graph[e.id].push(before);
    }
  }

  function hasCycle(node) {
    visited.add(node);
    recStack.add(node);

    for (const neighbor of graph[node] || []) {
      if (!visited.has(neighbor)) {
        if (hasCycle(neighbor)) return true;
      } else if (recStack.has(neighbor)) {
        return true;
      }
    }

    recStack.delete(node);
    return false;
  }

  for (const e of events) {
    if (!visited.has(e.id)) {
      if (hasCycle(e.id)) return true;
    }
  }

  return false;
}

function detectPreFlareWindows(readings, windowSize, threshold) {
  if (readings.length < windowSize) return 0;

  let count = 0;

  for (let i = 0; i <= readings.length - windowSize; i++) {
    let sum = 0, sumSq = 0;
    for (let j = i; j < i + windowSize; j++) {
      sum += readings[j];
      sumSq += readings[j] * readings[j];
    }
    const mean = sum / windowSize;
    const variance = sumSq / windowSize - mean * mean;
    const stdDev = Math.sqrt(variance);
    if (stdDev > threshold) count++;
  }

  return count;
}

function countViralPeriods(engagement, baseline, minDuration) {
  let periods = 0;
  let currentLen = 0;

  for (const e of engagement) {
    if (e > baseline) {
      currentLen++;
    } else {
      if (currentLen >= minDuration) {
        periods++;
      }
      currentLen = 0;
    }
  }

  if (currentLen >= minDuration) {
    periods++;
  }

  return periods;
}

function countPriceSurges(prices, windowSize, threshold) {
  // A surge is consecutive price increases where each exceeds the threshold
  if (prices.length < windowSize) return 0;

  let surges = 0;

  for (let i = 0; i <= prices.length - windowSize; i++) {
    let allIncreases = true;
    for (let j = i; j < i + windowSize - 1; j++) {
      const increase = ((prices[j + 1] - prices[j]) / prices[j]) * 100;
      if (increase <= threshold) {
        allIncreases = false;
        break;
      }
    }
    if (allIncreases) surges++;
  }

  return surges;
}

function countVolatileWindows(prices, windowSize, threshold) {
  if (prices.length < windowSize) return 0;

  let count = 0;

  for (let i = 0; i <= prices.length - windowSize; i++) {
    let min = prices[i], max = prices[i];
    for (let j = i + 1; j < i + windowSize; j++) {
      min = Math.min(min, prices[j]);
      max = Math.max(max, prices[j]);
    }
    // High volatility when range exceeds threshold (>)
    if (max - min > threshold) {
      count++;
    }
  }

  return count;
}

function optimizeSeating(tables, parties) {
  const available = {};

  for (const table of tables) {
    const key = table.size + "-" + table.area;
    available[key] = (available[key] || 0) + 1;
  }

  let seated = 0;

  for (const party of parties) {
    for (let size = party.size; size <= 8; size++) {
      const key = size + "-" + party.pref;
      if (available[key] && available[key] > 0) {
        available[key]--;
        seated++;
        break;
      }
    }
  }

  return seated;
}

function maxPaintingsOnWall(paintings, maxHeight) {
  paintings.sort((a, b) => a - b);

  let left = 0, right = paintings.length - 1;
  let count = 0, currentHeight = 0;

  while (left <= right) {
    if (currentHeight + paintings[left] <= maxHeight) {
      currentHeight += paintings[left];
      count++;
      left++;
    } else if (currentHeight + paintings[right] <= maxHeight) {
      currentHeight += paintings[right];
      count++;
      right--;
    } else {
      break;
    }
  }

  return count;
}

function longestGap(heights, minHeight) {
  let longest = 0;
  let current = 0;
  for (const h of heights) {
    if (h < minHeight) {
      current++;
      if (current > longest) longest = current;
    } else {
      current = 0;
    }
  }
  return longest;
}

function countRelicPairs(powers, target) {
  const seen = {};
  let pairs = 0;
  for (const value of powers) {
    const need = target - value;
    if (seen[need]) {
      pairs += seen[need];
    }
    seen[value] = (seen[value] || 0) + 1;
  }
  return pairs;
}

function optimizeMarsSupplyFlow(depots, routes, habitat) {
  const n = Math.max(...depots.map(d => d.id), habitat) + 1;
  const graph = Array(n).fill().map(() => Array(n).fill(0));

  const source = n;
  const newGraph = Array(n + 1).fill().map(() => Array(n + 1).fill(0));

  for (const [u, v, cap] of routes) {
    newGraph[u][v] += cap;
  }

  for (const depot of depots) {
    newGraph[source][depot.id] = depot.capacity;
  }

  function maxFlow(graph, s, t) {
    const n = graph.length;
    let flow = 0;

    while (true) {
      const parent = Array(n).fill(-1);
      const queue = [s];
      parent[s] = s;

      for (let i = 0; i < queue.length && parent[t] === -1; i++) {
        const u = queue[i];
        for (let v = 0; v < n; v++) {
          if (parent[v] === -1 && graph[u][v] > 0) {
            parent[v] = u;
            queue.push(v);
          }
        }
      }

      if (parent[t] === -1) break;

      let pathFlow = Infinity;
      for (let v = t; v !== s; v = parent[v]) {
        const u = parent[v];
        pathFlow = Math.min(pathFlow, graph[u][v]);
      }

      for (let v = t; v !== s; v = parent[v]) {
        const u = parent[v];
        graph[u][v] -= pathFlow;
        graph[v][u] += pathFlow;
      }

      flow += pathFlow;
    }

    return flow;
  }

  return maxFlow(newGraph, source, habitat);
}

function findOptimalSpell(runes, k, maxMana, requiredElements) {
  if (k === 0) return requiredElements.length === 0 ? 0 : -1;
  if (runes.length < k) return -1;

  const n = runes.length;
  let maxPower = -1;

  function backtrack(start, count, lastElement, currentPower, currentMana, elementsUsed) {
    if (currentMana > maxMana) return;

    if (count === k) {
      for (const elem of requiredElements) {
        if (!elementsUsed.has(elem)) return;
      }
      maxPower = Math.max(maxPower, currentPower);
      return;
    }

    if (start >= n) return;

    for (let i = start; i < n; i++) {
      const rune = runes[i];
      if (rune.element !== lastElement) {
        const newElements = new Set(elementsUsed);
        newElements.add(rune.element);
        backtrack(i + 1, count + 1, rune.element, currentPower + rune.power, currentMana + rune.power, newElements);
      }
    }
  }

  backtrack(0, 0, null, 0, 0, new Set());
  return maxPower;
}

function planMetroJourney(network, start, destination, blacklist, transferPenalty) {
  if (start === destination) return 0;
  if (blacklist.includes(start) || blacklist.includes(destination)) return -1;

  const dist = new Map();
  const pq = [];

  for (const neighbor of network[start] || []) {
    if (blacklist.includes(neighbor[0])) continue;
    const cost = neighbor[1];
    const key = `${neighbor[0]},${neighbor[2]}`;
    if (!dist.has(key) || dist.get(key) > cost) {
      dist.set(key, cost);
      pq.push([cost, neighbor[0], neighbor[2]]);
    }
  }

  pq.sort((a, b) => a[0] - b[0]);

  while (pq.length > 0) {
    const [currCost, station, line] = pq.shift();

    if (station === destination) return currCost;

    const key = `${station},${line}`;
    if (dist.has(key) && dist.get(key) < currCost) continue;

    for (const [next, time, nextLine] of network[station] || []) {
      if (blacklist.includes(next)) continue;

      const transferCost = line !== nextLine ? transferPenalty : 0;
      const newCost = currCost + time + transferCost;
      const nextKey = `${next},${nextLine}`;

      if (!dist.has(nextKey) || newCost < dist.get(nextKey)) {
        dist.set(nextKey, newCost);
        pq.push([newCost, next, nextLine]);
      }
    }
    pq.sort((a, b) => a[0] - b[0]);
  }

  let minCost = Infinity;
  for (const [key, cost] of dist) {
    if (key.startsWith(`${destination},`)) {
      minCost = Math.min(minCost, cost);
    }
  }

  return minCost === Infinity ? -1 : minCost;
}

function optimizeAntForaging(graph, foodSources, startNode, timeLimit) {
  const n = graph.length;
  const foodMap = new Map();
  for (const f of foodSources) {
    foodMap.set(f.node, f.value);
  }

  let maxValue = 0;

  function dfs(current, timeSpent, collected, value) {
    if (timeSpent > timeLimit) return;

    if (current === startNode && timeSpent > 0) {
      maxValue = Math.max(maxValue, value);
      return;
    }

    if (current === startNode && collected.size === foodSources.length) {
      maxValue = Math.max(maxValue, value);
      return;
    }

    for (let next = 0; next < n; next++) {
      if (graph[current][next] === 0) continue;

      const travelTime = graph[current][next];
      const newTime = timeSpent + travelTime;

      if (newTime > timeLimit) continue;

      const newCollected = new Set(collected);
      let newValue = value;

      if (foodMap.has(next) && !collected.has(next)) {
        newCollected.add(next);
        newValue += foodMap.get(next);
      }

      dfs(next, newTime, newCollected, newValue);
    }
  }

  for (let i = 0; i < n; i++) {
    if (i !== startNode && graph[startNode][i] > 0) {
      const travelTime = graph[startNode][i];
      if (travelTime <= timeLimit) {
        const collected = new Set();
        let value = 0;
        if (foodMap.has(i)) {
          collected.add(i);
          value = foodMap.get(i);
        }
        dfs(i, travelTime, collected, value);
      }
    }
  }

  return maxValue;
}

function planExcavation(artifacts, dependencies, timeBudget) {
  const n = artifacts.length;
  if (n === 0) return 0;

  const adj = Array(n).fill().map(() => []);
  const inDegree = Array(n).fill(0);
  const artifactMap = new Map();

  for (const art of artifacts) {
